A;AAEA;EACA,kBAAA;EACA,aAAA;EACA,yBAAA;AACA","sourcesContent":["<template>\n  <modal-shell\n    class=\"dm-preview-mask\"\n    :visible=\"visible\"\n    :title=\"title\"\n    width=\"450px\"\n    @close=\"onClose\"\n  >\n    <div ref=\"content\" class=\"dm-preview-content\" @scroll=\"onScroll\">\n      <table class=\"dm-preview-table\">\n        <thead class=\"dm-preview-thead\">\n          <tr>\n            <th class=\"dm-preview-sort-time\" @click=\"onSortToggle\">\n              时间 <span class=\"sort-icon\">{{ sortIcon }}</span>\n            </th>\n            <th class=\"dm-preview-col-text\">内容</th>\n          </tr>\n        </thead>\n        <tbody>\n          <tr v-for=\"(item, index) in items\" :key=\"`${item.time}-${index}`\" class=\"dm-preview-row\">\n            <td class=\"dm-preview-time\">{{ formatTime(item.time) }}</td>\n            <td class=\"dm-preview-text\">{{ item.text }}</td>\n          </tr>\n        </tbody>\n      </table>\n      <div v-show=\"hasMore\" class=\"dm-preview-loader\">滚动加载更多...</div>\n    </div>\n  </modal-shell>\n</template>\n\n<script lang=\"ts\">\nimport ModalShell from './shared/ModalShell.vue'\nimport { PREVIEW_MODAL_EVENTS, type MergerPreviewItem } from './contracts'\n\nfunction formatTime(seconds: number): string {\n  const m = Math.floor(seconds / 60)\n  const s = Math.floor(seconds % 60)\n  return `${m.toString().padStart(2, '0')}:${s.toString().padStart(2, '0')}`\n}\n\nexport default Vue.extend({\n  name: 'PreviewModal',\n  components: {\n    ModalShell,\n  },\n  // 根实例挂载，外部状态由 vue-host 写入 $data\n  data() {\n    return {\n      visible: false,\n      title: '',\n      items: [] as MergerPreviewItem[],\n      displayedCount: 0,\n      sortOrder: 1 as 1 | -1,\n      hasMore: false,\n      loadMoreLock: false,\n    }\n  },\n  computed: {\n    sortIcon(): string {\n      return this.sortOrder === 1 ? '▲' : '▼'\n    },\n  },\n  watch: {\n    sortOrder() {\n      this.resetScrollTop()\n    },\n    items() {\n      this.loadMoreLock = false\n    },\n  },\n  methods: {\n    formatTime,\n    onClose() {\n      this.$emit(PREVIEW_MODAL_EVENTS.CLOSE)\n    },\n    onSortToggle() {\n      const order = (this.sortOrder * -1) as 1 | -1\n      this.$emit(PREVIEW_MODAL_EVENTS.SORT_TOGGLE, { order })\n    },\n    onScroll() {\n      const el = this.$refs.content as HTMLElement | undefined\n      if (!el || !this.hasMore || this.loadMoreLock) {\n        return\n      }\n\n      if (el.scrollTop + el.clientHeight >= el.scrollHeight - 20) {\n        this.loadMoreLock = true\n        this.$emit(PREVIEW_MODAL_EVENTS.LOAD_MORE)\n      }\n    },\n    resetScrollTop() {\n      const el = this.$refs.content as HTMLElement | undefined\n      if (el) {\n        el.scrollTop = 0\n      }\n      this.loadMoreLock = false\n    },\n  },\n})\n</script>\n\n<style scoped>\n.dm-preview-mask {\n  z-index: 100020;\n}\n\n::v-deep .dm-merger-modal {\n  max-height: 70vh;\n}\n\n::v-deep .dm-merger-body {\n  padding: 0;\n  overflow: hidden;\n  display: flex;\n  flex-direction: column;\n  min-height: 0;\n}\n\n.dm-preview-content {\n  padding: 10px;\n  overflow-y: auto;\n  flex: 1;\n}\n\n.dm-preview-table {\n  width: 100%;\n  border-collapse: collapse;\n  font-size: 13px;\n}\n\n.dm-preview-thead {\n  position: sticky;\n  top: 0;\n  background: var(--bg1, #fff);\n  box-shadow: 0 1px 0 #eee;\n  z-index: 1;\n}\n\n.dm-preview-sort-time {\n  text-align: left;\n  padding: 8px;\n  color: #00aeec;\n  width: 80px;\n  cursor: pointer;\n  user-select: none;\n}\n\n.dm-preview-col-text {\n  text-align: left;\n  padding: 8px;\n  color: var(--text3, #999);\n}\n\n.dm-preview-row {\n  border-bottom: 1px solid var(--line_light, #f4f4f4);\n}\n\n.dm-preview-time {\n  padding: 8px;\n  color: #00aeec;\n  font-family: monospace;\n}\n\n.dm-preview-text {\n  padding: 8px;\n  color: var(--text1, #222);\n  word-break: break-all;\n}\n\n.dm-preview-loader {\n  text-align: center;\n  padding: 15px;\n  color: var(--text3, #999);\n}\n</style>\n"],"sourceRo